// Script Continued Below
// STRY0158283 - (DEFECT) As a basic user, users are able to see ALL task logs, email request, tasks, and response logs even of tasks they shouldn't
var taskFrom = current.getValue("tasker_instance_from") || '';
var taskTo = current.getValue("tasker_instance_to") || '';
// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives Task Requests permissions
var grTaskFrom = new GlideRecord("x_153465_discovert_route_task_instance");
var grTaskTo = new GlideRecord("x_153465_discovert_route_task_instance");
var allow = false;
if(taskFrom !='' && taskTo != ''){
	if(grTaskFrom.get(taskFrom) && grTaskTo.get(taskTo)){
		allow = grTaskFrom.canRead() && grTaskTo.canRead();
	}
}
answer = allow;
